//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagequicksightimport(	"context"	"fmt"	"log"	"strings"	"github.com/YakDriver/regexache"	"github.com/aws/aws-sdk-go/aws"	"github.com/aws/aws-sdk-go/service/quicksight"	"github.com/hashicorp/aws-sdk-go-base/v2/awsv1shim/v2/tfawserr"	"github.com/hashicorp/terraform-plugin-sdk/v2/diag"	"github.com/hashicorp/terraform-plugin-sdk/v2/helper/schema"	"github.com/hashicorp/terraform-plugin-sdk/v2/helper/validation"	"github.com/hashicorp/terraform-provider-aws/internal/conns"	"github.com/hashicorp/terraform-provider-aws/internal/errs/sdkdiag")const(	DefaultGroupNamespace="default")//@SDKResource("aws_quicksight_group",name="Group")funcResourceGroup()*schema.Resource{	return&schema.Resource{		CreateWithoutTimeout:resourceGroupCreate,		ReadWithoutTimeout:resourceGroupRead,		UpdateWithoutTimeout:resourceGroupUpdate,		DeleteWithoutTimeout:resourceGroupDelete,		Importer:&schema.ResourceImporter{			StateContext:schema.ImportStatePassthroughContext,		},		Schemafunc:func()map[string]*schema.Schema{			returnmap[string]*schema.Schema{				"arn":{					Type:schema.TypeString,					Computed:true,				},				"aws_account_id":{					Type:schema.TypeString,					Optional:true,					Computed:true,					ForceNew:true,				},				"description":{					Type:schema.TypeString,					Optional:true,				},				"group_name":{					Type:schema.TypeString,					Required:true,					ForceNew:true,				},				"namespace":{					Type:schema.TypeString,					Optional:true,					ForceNew:true,					Default:DefaultGroupNamespace,					Validatefunc:validation.All(						validation.StringLenBetween(1,63),						validation.StringMatch(regexache.MustCompile(`^[0-9A-Za-z_.-]*$`),"mustcontainonlyalphanumericcharacters,hyphens,underscores,andperiods"),					),				},			}		},	}}funcresourceGroupCreate(ctxcontext.Context,d*schema.ResourceData,metainterface{})diag.Diagnostics{	vardiagsdiag.Diagnostics	conn:=meta.(*conns.AWSClient).QuickSightConn(ctx)	awsAccountID:=meta.(*conns.AWSClient).AccountID	namespace:=d.Get("namespace").(string)	ifv,ok:=d.GetOk("aws_account_id");ok{		awsAccountID=v.(string)	}	createOpts:=&quicksight.CreateGroupInput{		AwsAccountId:aws.String(awsAccountID),		Namespace:aws.String(namespace),		GroupName:aws.String(d.Get("group_name").(string)),	}	ifv,ok:=d.GetOk("description");ok{		createOpts.Description=aws.String(v.(string))	}	resp,err:=conn.CreateGroupWithContext(ctx,createOpts)	iferr!=nil{		returnsdkdiag.AppendErrorf(diags,"creatingQuickSightGroup:%s",err)	}	d.SetId(fmt.Sprintf("%s/%s/%s",awsAccountID,namespace,aws.StringValue(resp.Group.GroupName)))	returnappend(diags,resourceGroupRead(ctx,d,meta)...)}funcresourceGroupRead(ctxcontext.Context,d*schema.ResourceData,metainterface{})diag.Diagnostics{	vardiagsdiag.Diagnostics	conn:=meta.(*conns.AWSClient).QuickSightConn(ctx)	awsAccountID,namespace,groupName,err:=GroupParseID(d.Id())	iferr!=nil{		returnsdkdiag.AppendErrorf(diags,"readingQuickSightGroup(%s):%s",d.Id(),err)	}	descOpts:=&quicksight.DescribeGroupInput{		AwsAccountId:aws.String(awsAccountID),		Namespace:aws.String(namespace),		GroupName:aws.String(groupName),	}	resp,err:=conn.DescribeGroupWithContext(ctx,descOpts)	if!d.IsNewResource()&&tfawserr.ErrCodeEquals(err,quicksight.ErrCodeResourceNotFoundException){		log.Printf("[WARN]QuickSightGroup(%s)notfound,removingfromstate",d.Id())		d.SetId("")		returndiags	}	iferr!=nil{		returnsdkdiag.AppendErrorf(diags,"readingQuickSightGroup(%s):%s",d.Id(),err)	}	d.Set("arn",resp.Group.Arn)	d.Set("aws_account_id",awsAccountID)	d.Set("group_name",resp.Group.GroupName)	d.Set("description",resp.Group.Description)	d.Set("namespace",namespace)	returndiags}funcresourceGroupUpdate(ctxcontext.Context,d*schema.ResourceData,metainterface{})diag.Diagnostics{	vardiagsdiag.Diagnostics	conn:=meta.(*conns.AWSClient).QuickSightConn(ctx)	awsAccountID,namespace,groupName,err:=GroupParseID(d.Id())	iferr!=nil{		returnsdkdiag.AppendErrorf(diags,"updatingQuickSightGroup(%s):%s",d.Id(),err)	}	updateOpts:=&quicksight.UpdateGroupInput{		AwsAccountId:aws.String(awsAccountID),		Namespace:aws.String(namespace),		GroupName:aws.String(groupName),	}	ifv,ok:=d.GetOk("description");ok{		updateOpts.Description=aws.String(v.(string))	}	_,err=conn.UpdateGroupWithContext(ctx,updateOpts)	iferr!=nil{		returnsdkdiag.AppendErrorf(diags,"updatingQuickSightGroup%s:%s",d.Id(),err)	}	returnappend(diags,resourceGroupRead(ctx,d,meta)...)}funcresourceGroupDelete(ctxcontext.Context,d*schema.ResourceData,metainterface{})diag.Diagnostics{	vardiagsdiag.Diagnostics	conn:=meta.(*conns.AWSClient).QuickSightConn(ctx)	awsAccountID,namespace,groupName,err:=GroupParseID(d.Id())	iferr!=nil{		returnsdkdiag.AppendErrorf(diags,"deletingQuickSightGroup(%s):%s",d.Id(),err)	}	deleteOpts:=&quicksight.DeleteGroupInput{		AwsAccountId:aws.String(awsAccountID),		Namespace:aws.String(namespace),		GroupName:aws.String(groupName),	}	if_,err:=conn.DeleteGroupWithContext(ctx,deleteOpts);err!=nil{		iftfawserr.ErrCodeEquals(err,quicksight.ErrCodeResourceNotFoundException){			returndiags		}		returnsdkdiag.AppendErrorf(diags,"deletingQuickSightGroup%s:%s",d.Id(),err)	}	returndiags}funcGroupParseID(idstring)(string,string,string,error){	parts:=strings.SplitN(id,"/",3)	iflen(parts)<3||parts[0]==""||parts[1]==""||parts[2]==""{		return"","","",fmt.Errorf("unexpectedformatofID(%s),expectedAWS_ACCOUNT_ID/NAMESPACE/GROUP_NAME",id)	}	returnparts[0],parts[1],parts[2],nil}